                        Spacer(modifier = Modifier.height(8.dp))
                        Text("Loading featured restaurants...", color = Color.Gray)
                    }
                }
            }

            restaurantError != null && featuredRestaurants.isEmpty() -> {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp),
