    restaurantViewModel: RestaurantViewModel = viewModel()
) {
    // Collect restaurant state - using featured and recommended APIs
    val featuredRestaurants by restaurantViewModel.featuredRestaurants.collectAsState()
    val recommendedRestaurants by restaurantViewModel.recommendedRestaurants.collectAsState()
    val isRestaurantsLoading by restaurantViewModel.isLoading.collectAsState()
    val restaurantError by restaurantViewModel.error.collectAsState()

    // Load restaurants from API for CHICKEN_HANDI category
    LaunchedEffect(Unit) {
        println("🚀 Loading FEATURED restaurants from API for category: CHICKEN_HANDI")
        restaurantViewModel.loadFeaturedRestaurants("CHICKEN_HANDI", featured = true)
        restaurantViewModel.loadRecommendedRestaurants("CHICKEN_HANDI", recommended = true)
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
    ) {
        Spacer(modifier = Modifier.height(15.dp))

        // Filter Button
        val chickenHandiFilters = FilterConfig(
            filters = listOf(
                // Main filter dropdown
                FilterChip(
                    id = "filters",
                    text = "Filters",
                    type = FilterType.FILTER_DROPDOWN,
                    icon = R.drawable.ic_filter,
                    rightIcon = R.drawable.outline_keyboard_arrow_down_24
                ),

                // CHICKEN TYPE (icons for distinctive types)
                FilterChip(
                    id = "bone_in",
                    text = "Bone-in Chicken",
                    type = FilterType.WITH_LEFT_ICON,
                    icon = R.drawable.ic_bone_in_chicken_handi
                ),
                FilterChip(
                    id = "boneless",
                    text = "Boneless Chicken",
                    type = FilterType.WITH_LEFT_ICON,
                    icon = R.drawable.ic_boneless_chicken_handi
                ),
                FilterChip(
                    id = "thigh_pieces",
                    text = "Thigh Pieces",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "breast_pieces",
                    text = "Breast Pieces",
                    type = FilterType.TEXT_ONLY
                ),

                // HANDI STYLE (icons for regional specialties)
                FilterChip(
                    id = "punjabi_handi",
                    text = "Punjabi Handi",
                    type = FilterType.WITH_LEFT_ICON,
                    icon = R.drawable.ic_punjabi_handi
                ),
                FilterChip(
                    id = "kashmiri_handi",
                    text = "Kashmiri Handi",
                    type = FilterType.WITH_LEFT_ICON,
                    icon = R.drawable.ic_kashmiri_handi
                ),
                FilterChip(
                    id = "dhaba_handi",
                    text = "Dhaba Style",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "dum_handi",
                    text = "Dum Handi",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "restaurant_special",
                    text = "Restaurant Special",
                    type = FilterType.TEXT_ONLY
                ),

                // GRAVY TYPE (icon for rich gravies)
                FilterChip(
                    id = "creamy_gravy",
                    text = "Creamy Gravy",
                    type = FilterType.WITH_LEFT_ICON,
                    icon = R.drawable.ic_creamy_gravy_handi
                ),
                FilterChip(
                    id = "butter_gravy",
                    text = "Butter Gravy",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "tomato_gravy",
                    text = "Tomato Gravy",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "cashew_gravy",
                    text = "Cashew Gravy",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "thick_gravy",
                    text = "Thick Gravy",
                    type = FilterType.TEXT_ONLY
                ),

                // SPICE LEVEL
                FilterChip(
                    id = "mild",
                    text = "Mild",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "medium_spice",
                    text = "Medium Spice",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "spicy",
                    text = "Spicy",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "extra_spicy",
                    text = "Extra Spicy",
                    type = FilterType.TEXT_ONLY
                ),

                // COOKING METHOD (icon for traditional clay pot)
                FilterChip(
                    id = "sealed_handi",
                    text = "Sealed Handi",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "open_handi",
                    text = "Open Handi",
                    type = FilterType.TEXT_ONLY
                ),

                // KEY INGREDIENTS (icon for special ingredients)
                FilterChip(
                    id = "with_butter",
                    text = "With Butter",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "with_yogurt",
                    text = "With Yogurt",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "dry_fruits",
                    text = "With Dry Fruits",
                    type = FilterType.TEXT_ONLY
                ),

                // ACCOMPANIMENTS
                FilterChip(
                    id = "with_naan",
                    text = "With Naan",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "with_rumali_roti",
                    text = "With Rumali Roti",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "with_jeera_rice",
                    text = "With Jeera Rice",
                    type = FilterType.TEXT_ONLY
                ),

                // SERVING SIZE (icon for family serving)
                FilterChip(
                    id = "couple_size",
                    text = "Couple Size",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "single_serve",
                    text = "Single Serve",
                    type = FilterType.TEXT_ONLY
                ),

                // PREPARATION TIME (icon for quick preparation)
                FilterChip(
                    id = "traditional_prep",
                    text = "Traditional Prep",
                    type = FilterType.TEXT_ONLY
                ),

                // READY TO EAT
                FilterChip(
                    id = "ready_to_eat",
                    text = "Ready to Eat",
                    type = FilterType.TEXT_ONLY
                ),
                FilterChip(
                    id = "heat_and_serve",
                    text = "Heat & Serve",
                    type = FilterType.TEXT_ONLY
                ),

                // SPECIAL OCCASIONS (icon for festive special)
                FilterChip(
                    id = "party_size",
                    text = "Party Size",
                    type = FilterType.TEXT_ONLY
                ),

                // Sort dropdown
                FilterChip(
                    id = "sort",
                    text = "Sort",
                    type = FilterType.SORT_DROPDOWN,
                    rightIcon = R.drawable.outline_keyboard_arrow_down_24
                ),
            ),
            rows = 2
        )
        FilterButtonFood(
            filterConfig = chickenHandiFilters,
            onFilterClick = { filter ->
                println("Filter clicked: ${filter.text}")
                // Apply filters to API calls based on selected filter
            },
            onSortClick = {
                println("Sort clicked")
                // Show sort options dialog
            }
        )

        Spacer(modifier = Modifier.height(5.dp))

        // ==================== RECOMMENDED CHICKEN HANDI ITEMS FROM API ====================
        Text(
            text = "Recommended for you",
            style = MaterialTheme.typography.bodySmall.copy(
                fontSize = 18.sp,
                fontWeight = FontWeight.Bold,
                color = MaterialTheme.customColors.black
            ),
            maxLines = 1,
            modifier = Modifier.fillMaxWidth().padding(start = 12.dp)
        )
        Spacer(modifier = Modifier.height(10.dp))

        when {
            isRestaurantsLoading && recommendedRestaurants.isEmpty() -> {
                Box(
                    modifier = Modifier.fillMaxWidth().padding(16.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        CircularProgressIndicator()
                        Spacer(modifier = Modifier.height(8.dp))
                        Text("Loading recommended chicken handi items...", color = Color.Gray)
                    }
                }
            }

            restaurantError != null && recommendedRestaurants.isEmpty() -> {
                Box(
                    modifier = Modifier.fillMaxWidth().padding(16.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(Icons.Default.Error, "Error", tint = Color.Red, modifier = Modifier.size(48.dp))
                        Spacer(modifier = Modifier.height(8.dp))
                        Text("Error: $restaurantError", color = Color.Red)
                        Spacer(modifier = Modifier.height(8.dp))
                        Button(onClick = {
                            restaurantViewModel.loadRecommendedRestaurants("CHICKEN_HANDI", recommended = true)
                        }) {
                            Text("Retry")
                        }
                    }
                }
            }

            recommendedRestaurants.isNotEmpty() -> {
                FoodItemsListWithHeadingDynamic(
                    heading = null,
                    subtitle = null,
                    foodItems = recommendedRestaurants.filter { it.recommended == true }.map { restaurant ->
                        FoodItemDoubleFDynamic(
                            id = restaurant.id,
                            imageUrl = restaurant.imageUrl,
                            title = restaurant.title,
                            price = restaurant.priceAvg,
                            restaurantName = restaurant.restaurantName,
                            rating = restaurant.rating,
                            deliveryTime = restaurant.deliveryTime,
                            distance = restaurant.distance,
                            discount = restaurant.discountAvg,
                            discountAmount = restaurant.discountAmountAvg,
                            address = restaurant.address?.city ?: restaurant.outlet,
                            isWishlisted = restaurant.isWishlisted
                        )
                    },
                    onItemClick = { foodItem ->
                        println("Food item clicked: ${foodItem.title}")
                        // TODO: Navigate to food item details
                    },
                    modifier = Modifier.fillMaxWidth(),
                    backgroundColor = Color.White,
                    cardWidth = 150.dp,
                    cardHeight = 170.dp,
                    horizontalSpacing = 8.dp,
                    horizontalPadding = 12.dp,
                    verticalPadding = 0.dp,
                    headingBottomPadding = 0.dp
                )
            }

            else -> {
                Box(
                    modifier = Modifier.fillMaxWidth().padding(32.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            painter = painterResource(R.drawable.ic_punjabi_handi),
                            contentDescription = "No recommended items",
                            modifier = Modifier.size(64.dp),
                            tint = Color.Gray
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        Text("No recommended chicken handi items found", fontSize = 16.sp, color = Color.Gray)
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(15.dp))

        // ==================== FEATURED CHICKEN HANDI RESTAURANTS FROM API ====================
        Text(
            text = "Restaurants delivering to you",
            style = MaterialTheme.typography.bodySmall.copy(
                fontSize = 20.sp,
                fontWeight = FontWeight.Bold,
                color = MaterialTheme.customColors.black
            ),
            maxLines = 1,
            modifier = Modifier.fillMaxWidth().padding(start = 12.dp)
        )
        Spacer(modifier = Modifier.height(10.dp))
        Text(
            text = "Featured restaurants",
            style = MaterialTheme.typography.bodySmall.copy(
                fontSize = 18.sp,
                fontWeight = FontWeight.Bold,
                color = MaterialTheme.customColors.black
            ),
            maxLines = 1,
            modifier = Modifier.fillMaxWidth().padding(start = 12.dp)
        )
        Spacer(modifier = Modifier.height(5.dp))

        when {
            isRestaurantsLoading && featuredRestaurants.isEmpty() -> {
                Box(
                    modifier = Modifier.fillMaxWidth().padding(16.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        CircularProgressIndicator()
                        Spacer(modifier = Modifier.height(8.dp))
                        Text("Loading featured chicken handi restaurants...", color = Color.Gray)
                    }
                }
            }

            restaurantError != null && featuredRestaurants.isEmpty() -> {
                Box(
                    modifier = Modifier.fillMaxWidth().padding(16.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(Icons.Default.Error, "Error", tint = Color.Red, modifier = Modifier.size(48.dp))
                        Spacer(modifier = Modifier.height(8.dp))
                        Text("Error: $restaurantError", color = Color.Red)
                        Spacer(modifier = Modifier.height(8.dp))
                        Button(onClick = {
                            restaurantViewModel.loadFeaturedRestaurants("CHICKEN_HANDI", featured = true)
                        }) {
                            Text("Retry")
                        }
                    }
                }
            }

            featuredRestaurants.isNotEmpty() -> {
                Column {
                    featuredRestaurants.filter { it.featured == true }.forEach { restaurant ->
                        RestaurantItemListFullDynamic(
                            restaurantItem = RestaurantItemFullDynamic(
                                id = restaurant.id,
                                imageUrl = restaurant.imageUrl,
                                title = restaurant.title,
                                price = restaurant.priceAvg,
                                restaurantName = restaurant.restaurantName,
                                rating = restaurant.rating,
                                deliveryTime = restaurant.deliveryTime,
                                distance = restaurant.distance,
                                address = restaurant.address?.city ?: restaurant.outlet,
                                discount = restaurant.discountAvg ?: "",
                                discountAmount = restaurant.discountAmountAvg ?: "",
                                isWishlisted = restaurant.isWishlisted
                            ),
                            onWishlistClick = { id ->
                                println("Wishlist clicked for featured restaurant: $id")
                                // TODO: Toggle wishlist status
                            },
                            onThreeDotClick = { id ->
                                println("Three dot clicked for featured restaurant: $id")
                                // TODO: Show more options dialog (share, report, etc.)
                            },
                            onItemClick = { id ->
                                println("Featured restaurant clicked: $id")
                                // TODO: Navigate to restaurant details
                            }
                        )
                    }
                }
            }

            else -> {
                Box(
                    modifier = Modifier.fillMaxWidth().padding(32.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            painter = painterResource(R.drawable.ic_bone_in_chicken_handi),
                            contentDescription = "No featured restaurants",
                            modifier = Modifier.size(64.dp),
                            tint = Color.Gray
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        Text("No featured chicken handi restaurants found", fontSize = 16.sp, color = Color.Gray)
                    }
                }
            }
        }
    }
}

